        .filter(o => getTime(o.dateTime) >= splitTime)
        .sort((a, b) => getTime(a.dateTime) - getTime(b.dateTime));

    const pastOrders = orders
        .filter(o => getTime(o.dateTime) < splitTime)
        .sort((a, b) => getTime(b.dateTime) - getTime(a.dateTime));

    const sortedOrders = [...upcomingOrders, ...pastOrders];

