        const url = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(order.title)}&dates=${formatTime(startDate)}/${formatTime(endDate)}&details=${encodeURIComponent(details)}&location=${encodeURIComponent(order.location.addressText || '')}`;

        window.open(url, '_blank');
